const SECTIONS = ["vocabulary","phrases","sentences","quiz","story","listening","speaking","conversation"];
const LABELS = { vocabulary:"📝 Vocab", phrases:"💬 Phrases", sentences:"✍️ Sentences", quiz:"🧩 Quiz", story:"📖 Story", listening:"🎧 Listening", speaking:"🎤 Speaking", conversation:"🤝 Conversation" };

export default function ProgressBar({ completedSections = {} }) {
  const done = SECTIONS.filter((s) => completedSections[s]).length;
  const pct = Math.round((done / SECTIONS.length) * 100);

  return (
    <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-4 mb-4">
      <div className="flex justify-between text-xs font-bold text-slate-500 mb-2">
        <span>📊 Today's Progress</span>
        <span>{pct}% · {done}/{SECTIONS.length} tasks</span>
      </div>
      <div className="h-3 bg-slate-100 rounded-full overflow-hidden border border-slate-200 mb-3">
        <div className="h-full bg-gradient-to-r from-blue-900 to-pink-500 rounded-full transition-all duration-700"
          style={{ width: `${pct}%` }} />
      </div>
      <div className="flex flex-wrap gap-1.5">
        {SECTIONS.map((s) => (
          <span key={s} className={`text-[10px] font-bold px-2 py-1 rounded-lg transition-all duration-300
            ${completedSections[s] ? "bg-green-100 text-green-700 border border-green-200" : "bg-slate-100 text-slate-400 border border-slate-200"}`}>
            {completedSections[s] ? "✓ " : ""}{LABELS[s]}
          </span>
        ))}
      </div>
    </div>
  );
}
